parameters.content:
/**
 * User notification preferences model.
 *
 * Controls how and when users receive notifications across multiple
 * channels: email, SMS, and webhook. Each channel has independent
 * enabled/subscribed-categories settings.
 *
 * History: Originally email-only (Session 3). Expanded to multi-channel
 * after SMS support was added (Session 8). Backward compatible — existing
 * email-only preferences continue to work; SMS and webhook default to enabled.
 */

import type { NotificationType, NotificationChannel } from './notification.js';

/**
 * Base per-channel preferences shared by all channels.
 * Each channel can be independently enabled/disabled and has its own
 * set of subscribed notification categories.
 */
export interface ChannelPreferences {
  /** Whether this channel is enabled for notifications. */
  enabled: boolean;

  /**
   * Notification categories the user is subscribed to on this channel.
   * If empty, user receives no category-based notifications on this channel.
   */
  subscribedCategories: NotificationType[];
}

/**
 * Email delivery frequency — controls batching behavior.
 * - 'immediate': send as events occur
 * - 'daily': batch into a daily digest
 * - 'weekly': batch into a weekly digest
 */
export type EmailFrequency = 'immediate' | 'daily' | 'weekly';

/**
 * Email channel preferences. Extends base with delivery frequency.
 */
export interface EmailPreferences extends ChannelPreferences {
  /** Delivery frequency for non-high-priority notifications. */
  frequency: EmailFrequency;
}

/**
 * SMS channel preferences.
 */
export interface SmsPreferences extends ChannelPreferences {}

/**
 * Webhook channel preferences.
 */
export interface WebhookPreferences extends ChannelPreferences {}

/**
 * Per-user notification preferences.
 */
export interface UserNotificationPreferences {
  /** User ID these preferences belong to. */
  userId: string;

  /** Master switch — when false, no notifications are sent at all. */
  enabled: boolean;

  /** Email-specific settings. */
  email: EmailPreferences;

  /** SMS-specific settings. */
  sms: SmsPreferences;

  /** Webhook-specific settings. */
  webhook: WebhookPreferences;

  /** When preferences were last updated. */
  updatedAt: Date;
}

/**
 * Input for updating notification preferences. All fields optional —
 * only provided fields are updated.
 */
export interface UpdatePreferencesInput {
  enabled?: boolean;
  email?: Partial<EmailPreferences>;
  sms?: Partial<SmsPreferences>;
  webhook?: Partial<WebhookPreferences>;
}

/** All notification categories — used as defaults. */
const ALL_CATEGORIES: NotificationType[] = [
  'order-confirmation',
  'order-status-update',
  'welcome',
  'account-update',
];

/**
 * Returns default preferences for a new user — everything enabled,
 * immediate email delivery, subscribed to all categories on all channels.
 */
export function getDefaultPreferences(userId: string): UserNotificationPreferences {
  return {
    userId,
    enabled: true,
    email: {
      enabled: true,
      frequency: 'immediate',
      subscribedCategories: [...ALL_CATEGORIES],
    },
    sms: {
      enabled: true,
      subscribedCategories: [...ALL_CATEGORIES],
    },
    webhook: {
      enabled: true,
      subscribedCategories: [...ALL_CATEGORIES],
    },
    updatedAt: new Date(),
  };
}

/**
 * Map a NotificationChannel to the corresponding preferences key.
 */
export function channelToPreferencesKey(channel: NotificationChannel): 'email' | 'sms' | 'webhook' | null {
  switch (channel) {
    case 'email': return 'email';
    case 'sms': return 'sms';
    case 'webhook': return 'webhook';
    default: return null;
  }
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Storage is in-memory (consistent with the rest of the codebase).
 * Users who haven't set preferences get defaults (all enabled, immediate).
 *
 * Supports per-channel preference checks: email, SMS, and webhook.
 * The generic shouldSend(userId, channel, type) method is the primary
 * interface for the NotificationService. Channel-specific convenience
 * methods (shouldSendEmail, shouldSendSms, shouldSendWebhook) are
 * also available.
 */

import type {
  UserNotificationPreferences,
  UpdatePreferencesInput,
  ChannelPreferences,
} from '../models/user-preferences.js';
import { getDefaultPreferences, channelToPreferencesKey } from '../models/user-preferences.js';
import type { NotificationType, NotificationChannel } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export class PreferencesService {
  private logger = new Logger('PreferencesService');
  private preferences: Map<string, UserNotificationPreferences> = new Map();

  /**
   * Get preferences for a user. Returns defaults if none are set.
   */
  getPreferences(userId: string): UserNotificationPreferences {
    const existing = this.preferences.get(userId);
    if (existing) {
      return {
        ...existing,
        email: { ...existing.email, subscribedCategories: [...existing.email.subscribedCategories] },
        sms: { ...existing.sms, subscribedCategories: [...existing.sms.subscribedCategories] },
        webhook: { ...existing.webhook, subscribedCategories: [...existing.webhook.subscribedCategories] },
      };
    }
    return getDefaultPreferences(userId);
  }

  /**
   * Update preferences for a user. Creates preferences if they don't exist.
   * Only provided fields are updated; others retain their current values.
   */
  updatePreferences(userId: string, input: UpdatePreferencesInput): UserNotificationPreferences {
    const current = this.getPreferences(userId);

    const updated: UserNotificationPreferences = {
      ...current,
      enabled: input.enabled ?? current.enabled,
      email: {
        enabled: input.email?.enabled ?? current.email.enabled,
        frequency: input.email?.frequency ?? current.email.frequency,
        subscribedCategories: input.email?.subscribedCategories ?? [...current.email.subscribedCategories],
      },
      sms: {
        enabled: input.sms?.enabled ?? current.sms.enabled,
        subscribedCategories: input.sms?.subscribedCategories ?? [...current.sms.subscribedCategories],
      },
      webhook: {
        enabled: input.webhook?.enabled ?? current.webhook.enabled,
        subscribedCategories: input.webhook?.subscribedCategories ?? [...current.webhook.subscribedCategories],
      },
      updatedAt: new Date(),
    };

    this.preferences.set(userId, updated);
    this.logger.info(`Updated preferences for user ${userId}`);
    return this.getPreferences(userId);
  }

  /**
   * Generic channel preference check. Returns whether a notification
   * should be sent to the user via the given channel for the given type.
   *
   * Channels without a preferences key (e.g. 'in-app') are always allowed.
   */
  shouldSend(userId: string, channel: NotificationChannel, notificationType: NotificationType): boolean {
    const prefs = this.getPreferences(userId);

    if (!prefs.enabled) {
      return false;
    }

    const key = channelToPreferencesKey(channel);
    if (!key) {
      // No preferences defined for this channel — allow by default
      return true;
    }

    const channelPrefs: ChannelPreferences = prefs[key];
    if (!channelPrefs.enabled) {
      return false;
    }

    return channelPrefs.subscribedCategories.includes(notificationType);
  }

  /**
   * Check whether a notification should be sent to a user via email.
   * Convenience wrapper around shouldSend — preserves backward compatibility.
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    return this.shouldSend(userId, 'email', notificationType);
  }

  /**
   * Check whether a notification should be sent to a user via SMS.
   */
  shouldSendSms(userId: string, notificationType: NotificationType): boolean {
    return this.shouldSend(userId, 'sms', notificationType);
  }

  /**
   * Check whether a notification should be sent to a user via webhook.
   */
  shouldSendWebhook(userId: string, notificationType: NotificationType): boolean {
    return this.shouldSend(userId, 'webhook', notificationType);
  }

  /**
   * Reset preferences for a user back to defaults.
   */
  resetPreferences(userId: string): UserNotificationPreferences {
    this.preferences.delete(userId);
    this.logger.info(`Reset preferences for user ${userId}`);
    return this.getPreferences(userId);
  }

  /**
   * Delete stored preferences for a user.
   */
  deletePreferences(userId: string): boolean {
    const existed = this.preferences.has(userId);
    this.preferences.delete(userId);
    return existed;
  }
}

