    notificationService.registerAdapter(emailAdapter);
    notificationService.registerAdapter(smsAdapter);
    notificationService.registerAdapter(webhookAdapter);
    preferencesService = new PreferencesService();
    notificationService.setPreferencesService(preferencesService);
    resetNotificationIdCounter();
  });

  const makeOrderCreatedEvent = (userId: string, email: string): OrderCreatedEvent => ({
    type: 'order:created',
    order: {
      id: 'order-1',
      userId,
      items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
      total: 10,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: userId,
      name: 'Alice',
      email,
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
  });

  it('should suppress SMS channel when SMS preferences are disabled', async () => {
    preferencesService.updatePreferences('user-1', {
      sms: { enabled: false },
    });
    // Email should still be allowed
    expect(preferencesService.shouldSend('user-1', 'email', 'order-confirmation')).toBe(true);
