    // order-confirmation: email yes, sms yes, webhook no
    expect(preferencesService.shouldSend('user-1', 'email', 'order-confirmation')).toBe(true);
    expect(preferencesService.shouldSend('user-1', 'sms', 'order-confirmation')).toBe(true);
    expect(preferencesService.shouldSend('user-1', 'webhook', 'order-confirmation')).toBe(false);

    // order-status-update: email no, sms no, webhook yes
    expect(preferencesService.shouldSend('user-1', 'email', 'order-status-update')).toBe(false);
    expect(preferencesService.shouldSend('user-1', 'sms', 'order-status-update')).toBe(false);
    expect(preferencesService.shouldSend('user-1', 'webhook', 'order-status-update')).toBe(true);
  });

  it('should suppress all channels when master switch is off', async () => {
    preferencesService.updatePreferences('user-1', { enabled: false });
    expect(preferencesService.shouldSend('user-1', 'email', 'order-confirmation')).toBe(false);
    expect(preferencesService.shouldSend('user-1', 'sms', 'order-confirmation')).toBe(false);
    expect(preferencesService.shouldSend('user-1', 'webhook', 'order-confirmation')).toBe(false);
  });

  it('should reset all channel preferences to defaults', () => {
    preferencesService.updatePreferences('user-1', {
      email: { enabled: false },
      sms: { enabled: false },
      webhook: { enabled: false },
    });
    const prefs = preferencesService.resetPreferences('user-1');
    expect(prefs.email.enabled).toBe(true);
    expect(prefs.sms.enabled).toBe(true);
    expect(prefs.webhook.enabled).toBe(true);
  });
});
